//! TLS 1.2 Cipher Tests
//!
//! This module tests the TLS 1.2 cipher decryption implementation using
//! test vectors generated by Python's cryptography library.

use tls_decryptor::cipher::suites::{
    TlsEcdheRsaWithChaCha20Poly1305Sha256, TlsRsaWithAes128GcmSha256, TlsRsaWithAes256GcmSha384,
};
use tls_decryptor::cipher::trait_def::CipherContext;

use super::hex_to_bytes;
use super::load_test_vectors;

#[test]
fn test_tls12_rsa_aes_128_gcm_decrypt() {
    let vectors = load_test_vectors();
    let test = &vectors["tls12_tests"]["rsa_aes_128_gcm_basic"];

    let cipher = TlsRsaWithAes128GcmSha256;
    let key = hex_to_bytes(test["key"].as_str().unwrap());
    let iv = hex_to_bytes(test["salt"].as_str().unwrap()); // TLS 1.2 uses salt as IV
    let ciphertext = hex_to_bytes(test["full_ciphertext"].as_str().unwrap());
    let aad = hex_to_bytes(test["aad"].as_str().unwrap());
    let expected_plaintext = hex_to_bytes(test["plaintext"].as_str().unwrap());

    let result = cipher
        .decrypt(&key, &iv, &ciphertext, &aad, 0)
        .expect("TLS 1.2 RSA AES-128-GCM decryption failed");

    assert_eq!(
        result, expected_plaintext,
        "TLS 1.2 RSA AES-128-GCM plaintext mismatch"
    );
}

