#[test]
fn test_tls12_cipher_context_properties() {
    let aes128 = TlsRsaWithAes128GcmSha256;
    assert_eq!(aes128.key_length(), 16);
    assert_eq!(aes128.iv_length(), 4); // TLS 1.2 GCM uses 4-byte salt
    assert_eq!(aes128.tag_length(), 16);
    assert!(aes128.needs_explicit_nonce());

    let aes256 = TlsRsaWithAes256GcmSha384;
    assert_eq!(aes256.key_length(), 32);
    assert_eq!(aes256.iv_length(), 4); // TLS 1.2 GCM uses 4-byte salt
    assert_eq!(aes256.tag_length(), 16);
    assert!(aes256.needs_explicit_nonce());

    let chacha = TlsEcdheRsaWithChaCha20Poly1305Sha256;
    assert_eq!(chacha.key_length(), 32);
    assert_eq!(chacha.iv_length(), 12);
    assert_eq!(chacha.tag_length(), 16);
    assert!(!chacha.needs_explicit_nonce()); // ChaCha20-Poly1305 doesn't use explicit nonce
}

#[test]
fn test_tls12_rsa_aes_128_gcm_invalid_key_length() {
    let cipher = TlsRsaWithAes128GcmSha256;
    let key = vec![0u8; 8]; // Invalid key length
    let iv = vec![0u8; 4];
    // TLS 1.2: explicit_nonce (8) + tag (16) = 24 bytes minimum
    let ciphertext = vec![0u8; 24];
    let aad = vec![];

    let result = cipher.decrypt(&key, &iv, &ciphertext, &aad, 0);
    assert!(result.is_err());
}

#[test]
fn test_tls12_rsa_aes_128_gcm_invalid_iv_length() {
    let cipher = TlsRsaWithAes128GcmSha256;
    let key = vec![0u8; 16];
    let iv = vec![0u8; 8]; // Invalid IV length (should be 4)
    let ciphertext = vec![0u8; 24];
    let aad = vec![];

    let result = cipher.decrypt(&key, &iv, &ciphertext, &aad, 0);
    assert!(result.is_err());
}

#[test]
fn test_tls12_rsa_aes_128_gcm_insufficient_data() {
    let cipher = TlsRsaWithAes128GcmSha256;
    let key = vec![0u8; 16];
    let iv = vec![0u8; 4];
    let ciphertext = vec![0u8; 4]; // Too short (less than explicit_nonce)
    let aad = vec![];

    let result = cipher.decrypt(&key, &iv, &ciphertext, &aad, 0);
    assert!(result.is_err());
}

